const email = $input.first().json;

// Extract invoice data from email body
const body = email.text || email.snippet || email.body || '';
const subject = email.subject || '';
const from = email.from || '';
const date = email.date || new Date().toISOString();

// Amount patterns: $1,234.56 / USD 1234.56 / 1,234.56 USD / Total: 1234.56
const amountPatterns = [
  /\$([\d,]+\.\d{2})/g,
  /USD\s*([\d,]+\.\d{2})/gi,
  /([\d,]+\.\d{2})\s*USD/gi,
  /total[:\s]+\$?([\d,]+\.\d{2})/gi,
  /amount[:\s]+\$?([\d,]+\.\d{2})/gi,
  /invoice[\s\w]*:\s*\$?([\d,]+\.\d{2})/gi
];

const amounts = [];
for (const pattern of amountPatterns) {
  let match;
  while ((match = pattern.exec(body)) !== null) {
    const num = parseFloat(match[1].replace(/,/g, ''));
    if (!isNaN(num) && num > 0) amounts.push(num);
  }
}

const maxAmount = amounts.length > 0 ? Math.max(...amounts) : 0;

// Invoice number patterns
const invPattern = /(?:invoice|inv|#)\s*[#:]?\s*([A-Z0-9\-]{4,20})/i;
const invMatch = (body + ' ' + subject).match(invPattern);
const invoiceNumber = invMatch ? invMatch[1] : `AUTO-${Date.now()}`;

// Vendor from email
const vendorMatch = from.match(/^(.+?)\s*</);
const vendor = vendorMatch ? vendorMatch[1].replace(/"/g, '').trim() : from.split('@')[0];

// Due date patterns
const dueDatePatterns = [
  /due\s+(?:by|on|date)[:\s]+([\w\s,]+\d{4})/i,
  /payment\s+due[:\s]+([\w\s,]+\d{4})/i
];
let dueDate = '';
for (const p of dueDatePatterns) {
  const m = body.match(p);
  if (m) { dueDate = m[1].trim().substring(0, 30); break; }
}

return [{
  json: {
    invoiceNumber,
    vendor,
    fromEmail: from,
    subject,
    amount: maxAmount,
    amountFormatted: maxAmount.toLocaleString('en-US', { style: 'currency', currency: 'USD' }),
    dueDate,
    emailDate: new Date(date).toLocaleDateString('en-US'),
    isHighValue: maxAmount >= 1000,
    emailId: email.id,
    snippet: body.substring(0, 200)
  }
}];
